import Navbar from "components/Navbars/AuthNavbar.js";
import EvaluationSection from "components/Common/evaluationsection";
import SocialFooter from "components/Common/socialFooter";

export default function EmployeeEvaluation() {
  const { id } = useParams();
  const location = useLocation();
  const history = useHistory();
  const employeeFromList = location.state?.employee || null;
  
  const [employee, setEmployee] = useState(null);
  const [loading, setLoading] = useState(true);
  const [workHistory, setWorkHistory] = useState([]);
  const [workerStatus, setWorkerStatus] = useState("working");
  const [currentWorkPlace, setCurrentWorkPlace] = useState(null);
  
  // قائمة أماكن العمل المتاحة
  const availablePlaces = [
    { id: 1, name: "Restaurant Andalous", icon: "🏪" },
    { id: 2, name: "Café Parisien", icon: "☕" },
    { id: 3, name: "La Piazza Italia", icon: "🍕" },
    { id: 4, name: "Sushi Master", icon: "🍣" },
    { id: 5, name: "Le Gourmet", icon: "🍽️" }
  ];
  
  // بيانات الموظفين
  const employeesData = {
    1: {
      id: 1,
      name: "Youssef",
      role: "Employé",
      profileImage: "https://randomuser.me/api/portraits/men/1.jpg",
      coverImage: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
      location: "Casablanca, Maroc",
      email: "youssef@example.com",
      phone: "+212 6 12 34 56 78",
      skills: ["Service client", "Rapidité", "Polyvalence"],
      bio: "Employé dévoué avec 3 ans d'expérience.",
      status: "working",
      currentPlace: { id: 1, name: "Restaurant Andalous", icon: "🏪" }
    },
    2: {
      id: 2,
      name: "Mohamed",
      role: "Employé",
      profileImage: "https://randomuser.me/api/portraits/men/2.jpg",
      coverImage: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
      location: "Rabat, Maroc",
      email: "mohamed@example.com",
      phone: "+212 6 98 76 54 32",
      skills: ["Gestion des stocks", "Organisation", "Travail d'équipe"],
      bio: "Employé sérieux et organisé.",
      status: "working",
      currentPlace: { id: 2, name: "Café Parisien", icon: "☕" }
    }
  };
  
  // بيانات التقييمات
  const mockWorkHistory = {
    1: [
      { id: 1, place: "Restaurant Andalous", role: "Employé", duration: "2024-01-15", rating: 5, review: "Excellent employé, très professionnel !" },
      { id: 2, place: "Café Central", role: "Stagiaire", duration: "2023-10-01", rating: 4, review: "Bon travail, à encouragé." }
    ],
    2: [
      { id: 1, place: "Café Parisien", role: "Employé", duration: "2024-02-01", rating: 4, review: "Travail correct, ponctuel." }
    ]
  };
  
  useEffect(() => {
    try {
      if (employeeFromList && employeeFromList.id) {
        setEmployee(employeeFromList);
        setWorkHistory(mockWorkHistory[employeeFromList.id] || []);
        setWorkerStatus(employeeFromList.status || "working");
        setCurrentWorkPlace(employeeFromList.currentPlace || availablePlaces[0]);
        setLoading(false);
      } 
      else if (id && employeesData[id]) {
        setEmployee(employeesData[id]);
        setWorkHistory(mockWorkHistory[id] || []);
        setWorkerStatus(employeesData[id].status || "working");
        setCurrentWorkPlace(employeesData[id].currentPlace || availablePlaces[0]);
        setLoading(false);
      } 
      else {
        setEmployee(employeesData[1]);
        setWorkHistory(mockWorkHistory[1] || []);
        setWorkerStatus("working");
        setCurrentWorkPlace(availablePlaces[0]);
        setLoading(false);
      }
    } catch (error) {
      console.error("Error loading employee:", error);
      setLoading(false);
    }
  }, [id, employeeFromList]);
  
  const handleAddEvaluation = (updatedHistory) => {
    setWorkHistory(updatedHistory);
    alert("✅ Évaluation ajoutée avec succès !");
  };
  
  const handleStatusChange = (newStatus) => {
    setWorkerStatus(newStatus);
    alert(`✅ Statut mis à jour : ${newStatus === 'working' ? 'En poste' : 'En recherche'}`);
  };
  
  const handleWorkPlaceChange = (place) => {
    setCurrentWorkPlace(place);
    alert(`✅ Lieu de travail changé : ${place.name}`);
  };
  
  const style = `
    .employee-evaluation-container {
      min-height: 100vh;
      width: 100%;
      background: #0a0a0a;
      position: relative;
    }
    
    .bg-gradient {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: radial-gradient(ellipse at 50% 30%, 
        #19022a 0%,
        #1c084b 30%,
        #1a0b2e 60%,
        #0a0a0a 85%,
        #050505 100%
      );
      z-index: 0;
    }
    
    .hero-image {
      position: absolute;
      top: 0;
      width: 100%;
      height: 100%;
      background-position: center 30%;
      background-size: cover;
    }
    
    .hero-overlay {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      background: linear-gradient(180deg, rgba(0,0,0,0.2) 0%, rgba(0,0,0,0.05) 30%, rgba(0,0,0,0) 50%, rgba(26,26,58,0.6) 100%);
    }
    
    .bg-white-card {
      background: rgba(255, 255, 255, 0.12);
      backdrop-filter: blur(16px);
      border-radius: 28px;
      border: 1px solid rgba(255, 255, 255, 0.25);
      box-shadow: 0 20px 40px rgba(0, 0, 0, 0.2);
    }
    
    .gradient-border-box {
      position: relative;
      width: 150px;
      height: 150px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 50%;
      margin-top: -60px;
      margin-left: -20px;
    }
    
    .gradient-border-box::before {
      content: "";
      position: absolute;
      inset: -4px;
      z-index: -1;
      background: linear-gradient(45deg, #ff0000, #ff7300, #fffb00, #48ff00, #00ffd5, #002bff, #7a00ff, #ff00c8, #ff0000);
      background-size: 450%;
      border-radius: 50%;
      animation: gradient-border 20s linear infinite;
      filter: blur(5px);
    }
    
    @keyframes gradient-border {
      0% { background-position: 0% 0%; }
      50% { background-position: 400% 0%; }
      100% { background-position: 0% 0%; }
    }
    
    .gradient-border-box .content {
      width: calc(100% - 4px);
      height: calc(100% - 4px);
      background-size: cover;
      background-position: center;
      border-radius: 50%;
      box-shadow: 0 0 30px rgba(0,0,0,0.3);
    }
    
    .profile-glow {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      width: 170px;
      height: 170px;
      background: radial-gradient(circle, rgba(34,197,94,0.3) 0%, rgba(34,197,94,0) 70%);
      border-radius: 50%;
      z-index: -1;
      animation: borderPulse 2s ease-in-out infinite;
    }
    
    @keyframes borderPulse {
      0%, 100% { opacity: 0.6; filter: blur(8px); }
      50% { opacity: 1; filter: blur(12px); }
    }
    
    .status-badge {
      display: inline-block;
      padding: 5px 12px;
      border-radius: 20px;
      font-size: 12px;
      font-weight: bold;
      margin-left: 10px;
      background: #22c55e;
      color: white;
    }
    
    .skill-tag {
      display: inline-block;
      padding: 4px 10px;
      background: rgba(34,197,94,0.2);
      border-radius: 15px;
      font-size: 11px;
      margin: 2px;
      color: #4ade80;
      border: 1px solid rgba(34,197,94,0.4);
      backdrop-filter: blur(5px);
    }
    
    .back-btn {
      position: fixed;
      top: 100px;
      left: 20px;
      z-index: 100;
      background: rgba(0,0,0,0.6);
      backdrop-filter: blur(10px);
      border: 1px solid rgba(34,197,94,0.3);
      border-radius: 40px;
      padding: 10px 20px;
      color: white;
      cursor: pointer;
      display: flex;
      align-items: center;
      gap: 8px;
      transition: all 0.3s;
    }
    
    .back-btn:hover {
      background: rgba(34,197,94,0.2);
      border-color: #22c55e;
      transform: translateX(-3px);
    }
    
    @media (max-width: 768px) {
      .gradient-border-box {
        width: 120px;
        height: 120px;
        margin-top: -50px;
        margin-left: 0;
      }
      
      .back-btn {
        top: 80px;
        left: 15px;
        padding: 6px 12px;
        font-size: 12px;
      }
    }
  `;

  if (loading) {
    return (
      <>
        <style>{style}</style>
        <Navbar />
        <div style={{ minHeight: "100vh", background: "#0a0a0a", display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ textAlign: "center", color: "white" }}>
            <div style={{ width: "50px", height: "50px", border: "3px solid rgba(255,255,255,0.2)", borderTopColor: "#22c55e", borderRadius: "50%", animation: "spin 1s linear infinite", margin: "0 auto 20px" }}></div>
            <p>Chargement...</p>
          </div>
          <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
        </div>
        <Footer />
      </>
    );
  }

  if (!employee) {
    return (
      <>
        <style>{style}</style>
        <Navbar />
        <div style={{ minHeight: "100vh", background: "#0a0a0a", display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ textAlign: "center", color: "white" }}>
            <h2>Employé non trouvé</h2>
            <button onClick={() => history.push("/manager")} style={{ background: "#22c55e", border: "none", padding: "10px 20px", borderRadius: "25px", color: "white", cursor: "pointer", marginTop: "20px" }}>Retour</button>
          </div>
        </div>
        <Footer />
      </>
    );
  }

  return (
    <>
      <style>{style}</style>
      <Navbar />
      
      <button className="back-btn" onClick={() => history.push("/manager")}>
        ← Retour
      </button>
      
      <div className="employee-evaluation-container">
        <div className="bg-gradient"></div>
        
        <main style={{ position: "relative", zIndex: 10 }}>
          <section className="relative block" style={{ height: "350px", position: "relative", overflow: "hidden" }}>
            <div className="hero-image" style={{ 
              backgroundImage: `url(${employee.coverImage || "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4"})`,
              backgroundSize: "cover",
              backgroundPosition: "center 40%"
            }}></div>
            <div className="hero-overlay"></div>
          </section>
          
          <section className="relative py-16 bg-transparent">
            <div className="container mx-auto px-4">
              <div className="relative flex flex-col min-w-0 break-words bg-white-card w-full mb-6 shadow-xl rounded-lg -mt-48">
                <div className="px-6">
                  
                  <div className="flex flex-wrap justify-center">
                    <div className="w-full lg:w-3/12 px-4 lg:order-2 flex justify-center">
                      <div className="profile-image-wrapper" style={{ position: "relative" }}>
                        <div className="profile-glow"></div>
                        <div className="gradient-border-box">
                          <img alt={employee.name} src={employee.profileImage} className="content" style={{ width: "100%", height: "100%", objectFit: "cover", borderRadius: "50%" }} />
                        </div>
                      </div>
                    </div>
                  </div>
                  
                  <div className="text-center mt-12">
                    <h3 className="text-4xl font-semibold leading-normal mb-2 text-white">
                      {employee.name}
                      <span className="status-badge">{workerStatus === "working" ? "✅ En poste" : "📢 En recherche"}</span>
                    </h3>
                    {workerStatus === "working" && currentWorkPlace && (
                      <p className="text-md text-green-400 font-semibold mt-2">📍 Travaille chez : {currentWorkPlace.name}</p>
                    )}
                    <div className="text-sm leading-normal mt-2 mb-2 text-gray-400 font-bold uppercase">
                      <i className="fas fa-map-marker-alt mr-2"></i> {employee.location}
                    </div>
                    <div className="mb-2 text-gray-300 mt-10">
                      <i className="fas fa-briefcase mr-2 text-green-400"></i> {employee.role}
                    </div>
                  </div>
                  
                  <div className="mt-6 py-4 border-t border-white/20">
                    <div className="flex flex-wrap justify-center">
                      <div className="w-full lg:w-9/12 px-4">
                        <p className="mb-4 text-lg leading-relaxed text-gray-200 italic">"{employee.bio}"</p>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {employee.skills && employee.skills.map((skill, i) => (
                            <span key={i} className="skill-tag">{skill}</span>
                          ))}
                        </div>
                      </div>
                    </div>
                  </div>
                  
                  {/* Section Évaluation */}
                  <div className="mt-6">
                    <EvaluationSection 
                      workHistory={workHistory}
                      onAddEvaluation={handleAddEvaluation}
                      canAddEvaluation={true}
                      currentWorkPlace={currentWorkPlace}
                      onStatusChange={handleStatusChange}
                      workerStatus={workerStatus}
                      availablePlaces={availablePlaces}
                      onWorkPlaceChange={handleWorkPlaceChange}
                    />
                  </div>
                  
                </div>
              </div>
            </div>
          </section>
        </main>
      </div>
      
      <SocialFooter socialLinks={{}} />
      <Footer />
    </>
  );
}
